"""
MKT Christ Commentary — 2 Chronicles chapters 21–24
Run: python3 scripts/zc-christ-2chronicles-21-24.py

Ch21: Jehoram — the Davidic lamp preserved through apostasy and judgment; Elijah's
      prophetic rebuke types John the Baptist's confrontation with Herod; bowel death
      as anti-type of resurrection life
Ch22: Athaliah's genocide and Jehoshabeath's hiding of Joash — the endangered royal
      seed preserved in the temple; types Egypt flight and the protected Messiah
Ch23: Joash's coronation — the hidden king revealed; testimony at anointing types
      Davidic Messiah; three-party covenant types new covenant mediation in Christ
Ch24: Temple restoration; Zechariah's Spirit-clothing and martyrdom (Matt 23:35);
      Jehoiada's priest-king burial types Melchizedek; prophetic rejection culminating
      in Christ
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "21": {
    "1": "<p>Jehoram inherits the Davidic throne from Jehoshaphat — a genealogical link in the royal chain that connects Judah's kings to the promise of an eternal throne (2 Sam 7:12-16). The Chronicler's careful succession notices serve a Christological purpose: every transition, however troubled, traces the line from which the anointed one will come. The name Jehoram ('YHWH is exalted') is ironic given his reign's character, but the continuity of the throne matters more than the character of any particular occupant — the promise runs through the lineage, not around it.</p>",
    "2": "<p>Jehoshaphat's six other sons receive silver, gold, precious things, and fortified cities — gifts that distribute the father's wealth while concentrating the kingdom in Jehoram. The contrast between the dispersed gifts and the concentrated throne anticipates the NT logic of Christ as the singular heir: 'heir of all things' (Heb 1:2), the one son who inherits the kingdom that cannot be shared. The brothers' gifts are temporal and material; the throne-right of the eldest (Jehoram) and ultimately of David's greater son is eternal and spiritual.</p>",
    "3": "<p>The father's blessing distributed to all sons before the kingdom narrows to one reflects the patriarchal typology throughout Chronicles: each generation narrows from many sons to the one who carries the covenantal destiny forward. Isaac over Ishmael, Jacob over Esau, Judah over his brothers, David over Jesse's sons, Solomon over his brothers — the pattern of divine election through genealogical narrowing culminates in the one son through whom all the covenant blessings come (Gal 3:16: 'to your offspring, which is Christ').</p>",
    "4": "<p>Jehoram murders his brothers 'with the sword' after establishing himself on his father's throne. The fratricide narrows the Davidic line violently and is the most extreme anti-type of the OT fratricidal pattern (Cain/Abel; Abimelech's 70 brothers; Absalom). Each brotherly murder in the royal line intensifies the vulnerability of the promise — how can an eternal throne be guaranteed through a lineage threatened by its own kings? The preservation of the line through these catastrophes becomes the OT's strongest argument for divine covenant faithfulness, establishing that the Messianic promise rests on YHWH's sovereignty, not the virtue of Davidic heirs.</p>",
    "5": "<p>Jehoram's 8-year reign at 32 — the shortest reign in Judah until Joash's son Amaziah — underscores the brevity of apostate kingship in the Chronicler's theology. The true Davidic king, by contrast, has a throne that is 'forever' (2 Sam 7:13; Ps 45:6: 'your throne, O God, is forever'). The contrast between Jehoram's compressed reign and the promised eternal kingship marks every faithless regent as a parenthesis — a failure mode that the true Son of David will permanently and irreversibly transcend.</p>",
    "6": "<p>Jehoram walks in the ways of the kings of Israel and marries Ahab's daughter — the Davidic-Omride alliance that introduced Baal worship into the southern kingdom. The marriage to Ahab's daughter (Athaliah) is the mechanism through which the most severe external threat to the Davidic line is introduced: Athaliah will survive Jehoram, survive Ahaziah, and nearly exterminate the royal seed entirely (22:10). The covenant faithlessness of the Davidic heir introduced through a dynastic marriage becomes the near-destruction of the Messianic line — the danger entering through the door of royal compromise.</p>",
    "7": "<p>YHWH refuses to destroy the house of David 'because of the covenant he had made with David, and since he had promised to give a lamp to him and to his sons forever.' The Davidic lamp (<em>nîr</em>) is the guarantee of royal continuity: even Jehoram's comprehensive apostasy cannot extinguish YHWH's commitment to maintain the Davidic line. This verse is the theological spine of the entire Judahite royal narrative — every bad king raises the question of whether the promise survives, and this answer is repeated each time: the covenant holds, not because of the king's virtue, but because YHWH gave his word. Luke 1:32-33 declares the fulfillment: 'The Lord God will give him the throne of his father David, and he will reign over the house of Jacob forever; his kingdom will have no end' — YHWH finally delivering the lamp in undying form.</p>",
    "8": "<p>Edom revolts and sets up its own king — the covenant territorial coherence of the Davidic kingdom fragmenting under a faithless king. David had subdued Edom (1 Chr 18:13); the reversal under Jehoram demonstrates that territorial blessing tracks covenant faithfulness. The expanding and contracting land under each king's faithfulness or apostasy is the OT's spatial representation of what Christ's kingdom makes permanent: a realm that cannot contract because it is secured not by royal virtue but by the King's own perfect righteousness (Rev 11:15: 'The kingdom of the world has become the kingdom of our Lord and of his Christ').</p>",
    "9": "<p>Jehoram breaks through the Edomite encirclement but fails to reconquer them — a partial military success that leaves the wound unhealed. The incomplete subjugation of Edom becomes in the prophetic tradition a symbol of the incomplete subjugation of all enemies (cf. Ps 60:8; 108:9 — 'Moab is my washbasin, over Edom I cast my shoe'). The final subjugation of all enemy nations is reserved for the Messiah: 'Ask of me, and I will make the nations your heritage, and the ends of the earth your possession' (Ps 2:8). Every incomplete military victory under Davidic kings is a promissory note pointing to the complete victory of the Son of David.</p>",
    "10": "<p>Libnah revolts 'because he had forsaken YHWH the God of his fathers' — the Chronicler's explicit causal chain: territorial loss follows covenant abandonment. Libnah is a priestly city in the Shephelah; its revolt has the character of a religious as well as political rupture. The NT parallel is the judgment on Jerusalem for forsaking the one who came to her: 'O Jerusalem, Jerusalem, killing the prophets... how often would I have gathered your children together... and you were not willing! Behold, your house is forsaken' (Matt 23:37-38). The pattern of covenant abandonment producing the forfeiture of promised inheritance is the OT grammar that Christ's lament over Jerusalem speaks.</p>",
    "11": "<p>Jehoram makes high places in the hill country of Judah and leads the inhabitants of Jerusalem into 'whoredom' — the prophetic metaphor for idolatry as covenant unfaithfulness (Hos 1-3; Jer 2:20; Ezek 16). The Davidic king as spiritual leader of the people means royal apostasy is not private sin but communal corruption: the king's whoredom is the nation's. Christ as the faithful covenant husband — the bridegroom who does not abandon his bride (Eph 5:25-27; Rev 19:7-9) — is the anti-type of every unfaithful Davidic regent who prostituted the covenant community through idolatry.</p>",
    "12": "<p>Elijah's letter to Jehoram — 'a letter came to him from Elijah the prophet' — is the only instance in Chronicles where Elijah appears, and only through a written communication. The letter charges Jehoram with walking in the ways of Ahab, murdering his brothers, and leading Judah astray. Elijah's function as the prophetic voice confronting royal wickedness is the same role John the Baptist will occupy in relation to Herod Antipas: 'John had been saying to him, it is not lawful for you to have your brother's wife' (Matt 14:4). Malachi 4:5 prophesied Elijah's return before the great day of YHWH; John the Baptist fulfills this in confronting the same pattern of royal moral corruption that Elijah addressed.</p>",
    "13": "<p>The charge 'you have also killed your brothers, your own family, who were better than yourself' draws the moral comparison that condemns Jehoram by his own standards: the victims were better than the perpetrator. The unjust death of the better at the hands of the worse — the innocent murdered by the guilty — is one of Scripture's recurring moral scandals that reaches its ultimate expression in Christ's crucifixion: the sinless one executed by sinners, the morally superior destroyed by the morally bankrupt. But in Christ's case, unlike Jehoram's brothers, the death of the better becomes the redemption of the worse (2 Cor 5:21).</p>",
    "14": "<p>YHWH announces a great plague on Jehoram's people, children, wives, and possessions — the covenant discipline spreading from king to nation. The solidarity between king and people means royal apostasy triggers communal judgment; the same solidarity means royal faithfulness can transfer communal blessing. The NT logic inverts this in Christ: one man's righteousness transfers covenant standing to the many (Rom 5:17-19: 'much more will those who receive the abundance of grace and the free gift of righteousness reign in life through the one man Jesus Christ'). Jehoram's solidarity-in-judgment is the negative of Christ's solidarity-in-justification.</p>",
    "15": "<p>YHWH's announcement of Jehoram's bowel disease is a divine word that precedes and determines the physical judgment — the prophetic word as the primary reality that the physical event enacts. The disease is 'incurable day by day' (<em>liḥolî yāmîm ʿal-yāmîm</em>); the progression toward death is inexorable once the divine word has been spoken. This pattern of divine word preceding and determining mortal outcome finds its redemptive parallel in Christ: the word spoken before the ages ('the Lamb slain before the foundation of the world,' Rev 13:8) determines the redemptive outcome just as surely as YHWH's word to Jehoram determines the judgment.</p>",
    "16": "<p>YHWH stirs up the Philistines and the Arabs against Jehoram — a divine stirring (<em>wayyāʿēr</em>) of enemy nations to serve as instruments of covenant discipline. The same verb appears in Isa 13:17 (YHWH stirs up the Medes against Babylon) and Jer 50:9 (YHWH stirs up nations against Babylon). In each case, human military action is simultaneously the free activity of nations and the intentional instrument of divine purpose. The crucifixion operates on the same logic: Pilate, Herod, Annas, and Caiaphas act freely and wickedly, while simultaneously fulfilling 'whatever your hand and your plan had predestined to take place' (Acts 4:27-28).</p>",
    "17": "<p>The Philistines and Arabs carry off all the possessions of Jehoram's house and all his sons 'except Ahaziah [Jehoahaz], the youngest of his sons.' Only the youngest son survives — the narrowest possible preservation of the Davidic royal line. From Jehoram's massacre of his brothers, to the raid that takes all but one son, the lineage through which the Messiah will come is repeatedly reduced to its barest minimum. Providence preserves one son where genealogical extinction seemed certain, so that 'a shoot from the stump of Jesse' (Isa 11:1) remains alive through each catastrophic pruning.</p>",
    "18": "<p>YHWH struck Jehoram in his bowels with an incurable disease — a divine action (<em>wayyigōp YHWH</em>) that targets the physical body as the instrument of judgment. The bowels (<em>mēʿāyw</em>) are in Hebrew idiom the seat of the deepest inner life — compassion (<em>raḥămîm</em>), anguish, the core of personhood. Jehoram's disease in the bowels is a physical judgment that strikes at the seat of inner vitality. By contrast, Ps 22:14 — a messianic psalm — describes the suffering servant: 'my heart is like wax; it is melted within my breast.' Christ's suffering is in the same bodily-spiritual register, but redemptive rather than punitive.</p>",
    "19": "<p>After two years his bowels came out because of the disease, and he died in great agony. The Chronicler includes the physical detail with unusual frankness — 'his bowels came out' (<em>wayᵉṣᵉʾû mēʿāyw bᵉmaḥălayyw</em>) — because the manner of death carries theological weight: it is a death as degrading as the sin was comprehensive. Acts 1:18 uses a similarly graphic description of Judas's death ('he burst open in the middle and all his bowels gushed out') — the NT's most direct parallel to Jehoram's end, applied to another betrayer of the Davidic covenant community. The degrading death of covenant traitors is the dark shadow of the voluntary, substitutionary death of the covenant keeper.</p>",
    "20": "<p>Jehoram 'departed without being lamented' (<em>wayyēlek bᵉlōʾ ḥemdāh</em>). The absence of the burial lament (<em>ḥemdāh</em> = desirability, beloved status) is the Chronicler's ultimate rejection formula: a king so dishonored that his passing generates no grief. The formula echoes Isa 53:2 in reverse: the Suffering Servant has 'no beauty that we should desire him' (<em>lōʾ-māreʾeh wᵉlōʾ hādār</em>) — despised and rejected in his earthly life, yet buried in a rich man's tomb (Isa 53:9) and raised to universal honor. Jehoram receives no honor in life or death; the true Davidic king is dishonored in death but receives the name above every name (Phil 2:9-11).</p>"
  },
  "22": {
    "1": "<p>The citizens of Jerusalem make Ahaziah (Jehoahaz) king — the sole surviving son of Jehoram, since all older sons were killed by the Arab raiders. The royal lineage has been narrowed to a single individual by two consecutive catastrophes (Jehoram's fratricide; the Arab raid). The Christological implication: the covenant promise is now concentrated in one person, whose protection is entirely dependent on divine faithfulness. The repeated near-extinction of the Davidic line before Christ's coming demonstrates that the Messiah arrives through YHWH's sovereign preservation, not through natural human probability.</p>",
    "2": "<p>The age discrepancy in Ahaziah's accession (42 in the MT vs. 22 in 2 Kgs 8:26 and most ancient versions) represents a copyist error in transmission — an error that itself testifies to the human frailty of the biblical record's preservation, held intact despite scribal imperfection. The promise of the Davidic line was preserved not because the textual record was incorruptible, but because YHWH's purpose could not be frustrated. The true Davidic king — Christ — comes not through a perfect documentary chain but through divine faithfulness superintending a flawed human record.</p>",
    "3": "<p>Ahaziah's mother Athaliah counseled him to do wickedly — the queen mother as the source of dynastic corruption. The queen mother (<em>gᵉḇîrāh</em>) held formal court position in Judah; Athaliah uses that position to transmit Omride apostasy into the Davidic court. The contrast with Mary, Christ's mother, is typologically stark: where Athaliah's influence corrupts the son and ultimately nearly destroys the royal line, Mary's faithful submission ('let it be to me according to your word,' Luke 1:38) enables the birth of the son who saves it.</p>",
    "4": "<p>Ahaziah walks in the ways of the house of Ahab — the Omride pattern fully replicating in the Davidic house through the marriage alliance. The Baal-influenced counsel of the house of Ahab becomes his destruction (v. 7). The infiltration of the covenant community by apostate influence from within — through royal marriage, counsel, and alliance — is the mechanism of internal corruption that Christ addresses at its root: 'I am the door' (John 10:7-9) — the true king who excludes corrupting influence rather than importing it, the shepherd who protects the flock from wolves rather than inviting them in.</p>",
    "5": "<p>Ahaziah goes with Joram son of Ahab to war against Hazael king of Syria at Ramoth-gilead — the site of Jehoshaphat's near-death (2 Chr 18) and Ahab's actual death (2 Chr 18:34). Ramoth-gilead is the location where the Omride dynasty's military ambitions meet divine judgment repeatedly. The alliance with the Omride dynasty in a militarily doomed campaign is the outworking of counsel received 'to his destruction' (v. 7). The pattern of Davidic kings being drawn into disaster by northern alliance is the OT's warning against yoking with the faithless — the warning Paul systematizes in 2 Cor 6:14: 'Do not be unequally yoked with unbelievers.'</p>",
    "6": "<p>Ahaziah visits the wounded Joram at Jezreel — the visit that places him at the location of Jehu's divinely commissioned purge. The visit is innocent in human terms (a family member visiting the sick) but brings him within reach of God's instrument of judgment. The Chronicler presents Ahaziah's location at the decisive moment not as accident but as divine arrangement: 'it was from God that the downfall of Ahaziah should come about' (v. 7). Providence uses ordinary human movement to place individuals at the intersection of divine purpose — the same divine geography that placed the magi in Bethlehem, the woman at the well in Samaria, and Zacchaeus in his sycamore tree.</p>",
    "7": "<p>'It was ordained by God that the downfall of Ahaziah should come about through his going to visit Joram' (<em>mēhāʾĕlōhîm hāyᵉtāh tᵉḇûssat ʾăḥazyāhû</em>). Divine determination works through Ahaziah's ordinary movement to bring about judgment. The theological principle is the Chronicler's clearest statement of providential causation: what appears as coincidence (a family visit) is divine appointment. The same divine determination governs the crucifixion: Judas's betrayal, Pilate's weakness, the Sanhedrin's envy are simultaneously free human acts and the outworking of what 'God had foreknown and predestined' (Acts 2:23). Providence governs downfall (Ahaziah) and salvation (Christ) with equal sovereignty.</p>",
    "8": "<p>Jehu executes judgment on the princes of Judah and on the sons of Ahaziah's brothers who were attending him — a comprehensive purge of the Omride-allied Davidic princes. The Davidic line is being decimated from within (Athaliah's influence) and without (Jehu's purge). Jehu is described in 2 Kgs 9:6-7 as anointed by YHWH's prophet to purge the house of Ahab and avenge the blood of the prophets. The instrument of prophetic avenging, acting under divine commission, nevertheless kills Judahite princes — a reminder that divine instruments operate at a level of judgment that exceeds careful discrimination, a violence that the cross alone resolves through the innocent taking the guilty's punishment.</p>",
    "9": "<p>Ahaziah sought to hide but was found, brought to Jehu, and executed. The note that he received burial 'because they said, he is the grandson of Jehoshaphat, who sought the LORD with all his heart' is a remarkable piece of grace-through-genealogy: Ahaziah's burial honor is extended not because of his own faithfulness but because of his grandfather's. The Chronicler presents covenant merit as trans-generational: Jehoshaphat's faithful seeking of YHWH extends even to a grandson who did not share that seeking. This logic finds its ultimate form in Christ: the righteousness of the greater Son of David is credited to those who share his genealogy through faith (Rom 4:22-24).</p>",
    "10": "<p>Athaliah kills 'all the royal family of the house of Judah' — the most systematic attempt to extinguish the Davidic line in the entire OT. A non-Davidic Omride woman seizes power over Judah by destroying every claimant to the Davidic throne. The covenant promise appears to be annihilated: the throne is occupied by a usurper; the heirs are dead. This is the OT's closest analog to the Herodian massacre of the innocents (Matt 2:16-18) — Herod's attempt to kill the Davidic heir by killing all potential rivals. In both cases, one child escapes: here Joash; there Jesus. The preservation of the one is the preservation of the promise.</p>",
    "11": "<p>Jehoshabeath the daughter of the king hid Joash in a bedroom and put him in her care, so that Athaliah could not put him to death. The temple becomes the hiding place of the Davidic heir — 'they hid him... in the house of God' (<em>ûtaṣpinēhû bêt hāʾĕlōhîm</em>). The sanctuary that was built to be the dwelling-place of YHWH becomes the refuge of the Davidic heir. The typological correspondence to Christ's hidden years is explicit: Joseph takes Mary and the child Jesus to Egypt to hide him from Herod (Matt 2:13-14). The true king of Israel is hidden in a foreign house of safety while a usurper reigns in Jerusalem — the pattern of the concealed Messiah whose time has not yet come.</p>",
    "12": "<p>Joash is hidden in the house of God for six years while Athaliah reigns over the land. Six years of concealment in the sanctuary — the sacred space that his father's house had polluted through Baal worship is now the hiding place of the legitimate heir. The temple as asylum echoes in the NT: Christ cleansing the temple (Matt 21:12-13) reclaims the Father's house from those who had profaned it, just as Jehoiada's restoration will reclaim it from Athaliah's influence. The hidden king in the temple for six years before the seventh-year revelation carries sabbatical resonance — the reign of usurpation giving way to the covenant restoration.</p>"
  },
  "23": {
    "1": "<p>In the seventh year Jehoiada strengthened himself and made a covenant with the military commanders. The 'seventh year' has sabbatical weight: after six years of illegitimate rule (the number of human completeness), the seventh year (completion of the covenant cycle) inaugurates the restoration of the Davidic heir. The covenant Jehoiada makes with the commanders to reveal the hidden king is the ecclesiastical-military alliance that enables legitimate kingship to emerge from its concealment. Christ's public ministry begins after hidden years in Nazareth; John's baptism is the equivalent moment of Jehoiada's covenant-making — organizing the community for the king's revelation.</p>",
    "2": "<p>Jehoiada gathers the Levites from all the cities of Judah and the heads of the fathers' houses of Israel to Jerusalem — an all-Israel assembly for the coronation. The breadth of the assembly (all cities, all tribal heads) gives the act of restoration its legitimacy: this is not a coup but a covenant assembly recognizing the rightful king. The same all-Israel logic governs the Pentecost assembly in Acts 2 — 'devout Jews from every nation under heaven' (Acts 2:5) gathered to witness the enthronement of Christ at God's right hand, the great Davidic coronation that the resurrection makes public.</p>",
    "3": "<p>The assembly makes a covenant with the king's son in the house of God. Jehoiada shows them the son of the king — the moment of royal revelation. The phrase 'behold, the son of the king shall reign' (<em>hinnēh ben-hammelek yimlōk</em>) is a proclamation of legitimate Davidic kingship over against the usurper. The NT parallel is John 1:29: 'Behold, the Lamb of God' — the Baptist's proclamation that reveals the hidden king, the Son who has come to rule. Both proclamations: 'this is the one; here he is; behold the king' — inaugurate the public phase of the hidden king's mission.</p>",
    "4": "<p>Jehoiada organizes the priests and Levites into guard rotations for the temple — the sacred structure enabling the king's safety. The temple as the organizing center of the coup is the Chronicler's presentation of the legitimate cult as the institutional guardian of legitimate kingship. The church as the pillar and buttress of truth (1 Tim 3:15) — the covenant community as the institutional guardian of the message of the true king — is the NT continuation of this priestly-royal partnership. The Levitical rotations guarding the threshold prefigure the church's ongoing witness that guards the testimony of Christ.</p>",
    "5": "<p>A third of the Levites are to guard the king's house, a third at the gate of the foundation (Sur Gate), a third at the temple gates — three guard detachments ensuring that no unauthorized person enters the temple during the coronation. The three-part guard distribution forms a complete perimeter around the zone of sacred action. The three witnesses at Christ's transfiguration (Peter, James, John) and the three women at the tomb serve analogous witnessing functions — the core testimony-community present at the moment of royal revelation.</p>",
    "6": "<p>Only the priests and ministering Levites are to enter; everyone else is to keep the charge of YHWH. The distinction between those who may approach and those who must keep distance is the fundamental structure of holy access that Christ's death permanently restructures: 'the veil of the temple was torn in two from top to bottom' (Matt 27:51), opening the way for all to enter the holiest place through the blood of Jesus (Heb 10:19-20). Jehoiada's strict access control at the Joash coronation is the OT order that the Christological event permanently and irreversibly opens.</p>",
    "7": "<p>The Levites are to surround the king, each with weapons in hand, to kill anyone who enters the sanctuary. The lethal guard around the legitimate king — to prevent the usurper or her allies from reaching him — is the protective logic that the NT theology of spiritual warfare continues: the powers of darkness cannot finally reach the enthroned king (Col 2:15: 'he disarmed the rulers and authorities and put them to open shame by triumphing over them in him'). Christ is beyond the reach of his enemies not because of armed guard but because of resurrection — the last enemy (death itself) has been defeated.</p>",
    "8": "<p>The Levites obey Jehoiada completely — 'each brought his men who were to go off duty on the Sabbath, with those who were to come on duty on the Sabbath.' The Sabbath day chosen for the coronation is not incidental: the day of covenant rest is the day the Davidic rest-giver is revealed. Solomon's temple was dedicated at the Feast of Tabernacles; Christ's resurrection occurs on the first day of the week (the day after the Sabbath); these cultic moments cluster around the calendar's markers of divine completion. Jehoiada chooses the Sabbath for the covenant renewal that installs the king of rest.</p>",
    "9": "<p>Jehoiada distributes the spears, shields, and large shields of King David that were in the house of God to the commanders. The weapons used to protect the Davidic heir are David's own weapons — the covenant king's armory protects the covenant king's heir. The spiritual armory Paul describes in Eph 6:10-18 is similarly the equipment of the covenant warrior, given to the covenant community to defend the advance of Christ's kingdom. The armor of God is not merely metaphor — it draws on the specific logic of sanctuary weapons deployed in the service of legitimate kingship.</p>",
    "10": "<p>The armed guard forms a complete cordon from the south side to the north side of the altar and the temple — a protective perimeter around the king. The architectural totality of the guard (south side to north side, temple entry to altar) positions the king at the protected center of the covenant structure. Christ at the center of his church — 'where two or three are gathered in my name, there am I among them' (Matt 18:20) — is the NT form of the protected-king-at-the-sanctuary-center.</p>",
    "11": "<p>They brought out the king's son, put on him the crown and gave him the testimony (<em>hāʿēḏût</em>), and made him king. Jehoiada and his sons anointed him (<em>wayyimšāḥû ʾōtô</em>) and they said: 'Long live the king!' The coronation has three elements: the crown (royal authority), the testimony (the covenant document — likely the Deuteronomic law per Deut 17:18-20), and the anointing (Spirit-authorization). These three elements correspond to Christ's enthronement: at his baptism he receives Spirit-anointing (Matt 3:16), he embodies the Torah (Matt 5:17: 'I have not come to abolish'), and he is declared the king at the resurrection (Acts 2:36: 'God has made him both Lord and Christ'). The Joash coronation is the OT covenant-coronation template for the Christological fulfillment.</p>",
    "12": "<p>Athaliah hears the sound of the people running, the praise, and the trumpets and comes to the temple. The usurper comes to investigate the sound of legitimate covenant worship — the celebration of the true king is what draws and exposes her. The public enthronement of the rightful king, proclaimed with music and liturgical shouts, is itself the mechanism that forces the illegitimate claimant into the open. Christ's resurrection proclamation similarly forces a confrontation: those who have claimed authority in his absence must respond to the announcement of his vindicated kingship.</p>",
    "13": "<p>Athaliah sees the king standing by his pillar at the entrance, the commanders and trumpeters beside the king, all the people rejoicing and trumpeting, and the singers with musical instruments leading the praise. She tears her clothes and cries 'Treason! Treason!' (<em>qešer qāšer</em>). The usurper calls the restoration of the legitimate king treason — inverting the moral order: the true king's return is called rebellion by the one who rebelled against him. The NT parallel is the repeated charge against Christ and his followers: 'these men who have turned the world upside down have come here also' (Acts 17:6). The world order built on rejection of the true king calls his restoration a subversion.</p>",
    "14": "<p>Jehoiada orders Athaliah to be brought out of the sanctuary and killed — 'Do not put her to death in the house of YHWH.' The usurper is removed from the sacred space before execution; the sanctuary is not to be defiled by her blood. The principle that the place of God's presence must not be contaminated by the violence of judgment against the guilty corresponds to the NT theology of Christ's blood shed 'outside the gate' (Heb 13:12-13): the holy place is kept clean; the judgment is carried out at a remove. Golgotha is outside Jerusalem; Athaliah is executed outside the sanctuary.</p>",
    "15": "<p>Athaliah is killed at the Horse Gate of the palace — the execution site is the boundary between the royal house and the city, the point of commerce and movement. The usurper dies at the threshold of the power she illegitimately seized. In Revelation's imagery, the beast and false prophet — usurpers of divine authority — are 'thrown alive into the lake of fire' (Rev 19:20) at Christ's return, the final removal of all illegitimate claimants to the throne that belongs to the one the Joash narrative typifies.</p>",
    "16": "<p>Jehoiada makes a covenant between himself, all the people, and the king to be YHWH's people. The three-party covenant — priest, people, king — to be YHWH's covenant community is the restoration of the foundational Sinaitic structure: YHWH-mediator-people-king. The covenant renewal that installs the legitimate king and reconstitutes the people around YHWH is the OT form of the new covenant Christ mediates: 'Jesus, the mediator of a new covenant' (Heb 12:24) — a three-party covenant between God, the mediating Son, and the people bound to him in faith. Jehoiada's mediation types the priestly mediation of Christ, who brings priest, king, and people into unified covenant relation.</p>",
    "17": "<p>All the people went to the house of Baal and tore it down, smashed its altars and images, and killed Mattan the priest of Baal before the altars. The covenant renewal instantly produces iconoclastic action: the reconstituted covenant community destroys the apparatus of the usurper's religion. The connection between restored covenant and destroyed idolatry is the Chronicler's consistent pattern (cf. Asa in 14:3; Hezekiah in 31:1; Josiah in 34:3-7). Christ's cleansing of the temple (Matt 21:12-13) follows the same sequence: restoration of the true covenant-king followed by expulsion of what defiled the covenant space.</p>",
    "18": "<p>Jehoiada assigns the oversight of the temple of YHWH to the Levitical priests, whom David had organized to offer the burnt offerings of YHWH as written in the Law of Moses, with rejoicing and singing according to the order of David. The restoration of the Davidic musical-liturgical order alongside the Mosaic sacrificial order represents the integration of the two streams of OT worship that point to Christ: the sacrificial system (fulfilled in Christ's atoning death) and the Davidic praise order (fulfilled in the church's worship 'in spirit and truth,' John 4:23). Jehoiada's restoration combines both, prefiguring the new covenant worship that unites them in Christ.</p>",
    "19": "<p>Jehoiada posts gatekeepers at the gates of the house of YHWH so that no one who was unclean in any way could enter. The purified access to the presence of God — after the desecration of Athaliah's reign — is reinstated through careful boundary-keeping. The principle of holy access is maintained: the presence of YHWH is not infinitely tolerant of all who approach. Christ himself will speak of the narrow gate (Matt 7:13-14) and the door through which the sheep enter (John 10:7-9). But the new covenant's gatekeeping is defined not by ritual purity but by faith in the one who is himself the gate: 'No one comes to the Father except through me' (John 14:6).</p>",
    "20": "<p>Jehoiada and the commanders, the nobles, and the rulers of the people bring Joash from the temple down through the upper gate to the palace; he takes his seat on the throne of the kings. The movement from sanctuary to throne room is the installation sequence: the king revealed in the holy place takes his seat in the royal house. The NT sequence is the inverse but parallel: Christ descends from the Father's presence into the world, accomplishes his saving work, and then ascends to the throne at God's right hand (Acts 2:33: 'being therefore exalted at the right hand of God'). Temple-to-throne is the direction of both coronations.</p>",
    "21": "<p>All the people of the land rejoiced, and the city was quiet, because Athaliah had been killed with the sword. The shalom of the city after the usurper's removal is a sabbath-image: the proper ruler installed, the illegitimate reign ended, peace restored to the community. Isaiah 9:6-7 describes the coming Davidic king as 'Prince of Peace' whose 'government and of his peace there will be no end.' The quiet that follows Athaliah's death is the OT's local, temporal form of the eschatological peace Christ's reign permanently establishes: 'the God of peace will soon crush Satan under your feet' (Rom 16:20).</p>"
  },
  "24": {
    "1": "<p>Joash begins to reign at 7 years old and reigns 40 years in Jerusalem — the number 40 carrying wilderness-wandering and covenant-testing resonance. The child-king installed by the faithful priest has the longest reign of Judah's genuinely restored kings until Uzziah's 52 years. But the 40-year reign is divided: the first half under Jehoiada's guidance is faithful; the second half after Jehoiada's death apostatizes. The divided reign of Joash is the OT's clearest portrait of conditional, dependent faithfulness — a king who does right only so long as he has a faithful mediator. Christ's reign has no such dependency: his faithfulness is intrinsic, not borrowed from a mentor.</p>",
    "2": "<p>'Joash did what was right in the eyes of YHWH all the days of Jehoiada the priest.' The qualification 'all the days of Jehoiada' is the Chronicler's most explicit statement of the problem of mediated faithfulness: the king's spiritual condition depends entirely on the continued presence of a godly intermediary. When the mediator dies, the king defaults to corruption. The new covenant addresses this structural problem: Christ the mediator does not die and leave the covenant community without mediation (Heb 7:24-25: 'he holds his priesthood permanently... he always lives to make intercession'). The permanent living mediation of Christ means the covenant community's faithfulness is no longer dependent on any mortal intermediary.</p>",
    "3": "<p>Jehoiada takes two wives for Joash, and he has sons and daughters — the perpetuation of the Davidic line through priestly arrangement. The priest securing the king's succession is an inversion of the usual order (kings secure priestly succession); here the priestly-royal partnership reverses the normal hierarchy so that the covenant line is preserved through priestly initiative. Melchizedek (Ps 110:4; Heb 7) is the OT's archetype of the priest who is also king; in the Joash narrative, the priest secures the king's genealogical continuation. Christ as the Melchizedekian priest-king unifies the roles that Jehoiada and Joash divide between them.</p>",
    "4": "<p>Joash's heart was to restore the house of YHWH — the king's primary covenant ambition is the renewal of the sanctuary. The temple as the center of Davidic theological identity means its restoration is the most important royal act. The NT's temple theology transforms this: Christ's body is the temple (John 2:19-21), and the church as the body of Christ is the new temple (1 Cor 3:16-17; Eph 2:19-22). The restoration of the physical temple under Joash typifies the building of the eschatological temple through Christ's death and resurrection — the construction of a dwelling of God 'not made with hands' (Mark 14:58).</p>",
    "5": "<p>Joash sends the Levites through all Israel to collect money from all Israel for the annual repair of the temple — a tax that had apparently lapsed. The national collection for the temple's maintenance is an all-Israel affair: even the divided north is included in the royal letter (<em>kol-yiśrāʾēl</em>). The appeal to all Israel for the sanctuary's restoration types the universal scope of the new covenant's assembly: Christ gathers from all nations (Rev 7:9), not merely Judah or even Israel, for the building of the eschatological sanctuary.</p>",
    "6": "<p>Joash summons Jehoiada the chief priest and charges him: 'Why have you not required the Levites to bring in from Judah and Jerusalem the tax levied by Moses the servant of God and the congregation of Israel for the tent of testimony?' The appeal to the Mosaic tent of testimony (<em>ʾōhel hāʿēḏût</em>) as the founding covenant structure that the temple continues invokes the wilderness sanctuary. Christ is the one in whom the original <em>ʾōhel</em>-presence dwells permanently — 'the Word became flesh and <em>tabernacled</em> among us' (John 1:14, using the Greek <em>eskēnōsen</em> = pitched his tent).</p>",
    "7": "<p>The sons of Athaliah, the wicked woman, had broken into the house of God and had also used all the dedicated things of the house of YHWH for the Baals. The temple vessels used in Baal worship during the interregnum are the OT's image of the sacred corrupted for profane use — the covenant instruments diverted to idolatrous purpose. Christ's cleansing of the temple (Matt 21:12-13; John 2:14-16) addresses the same category of corruption: the Father's house made into 'a den of robbers,' the sacred space and its instruments diverted from their covenant purpose.</p>",
    "8": "<p>A chest is made at the king's command and set outside the gate of the house of YHWH — the collection vessel for the temple restoration fund. The chest placed at the threshold of the sanctuary is the point where the covenant community's resources are received and redirected toward the holy. The NT parallel is the widow's offering observed by Jesus (Mark 12:41-44): the treasury at the temple gate where contributions are deposited, and the one who gives everything she has to the restoration of the place where God is worshipped. Christ commends the widow's giving as the truest form of what Joash's chest represents.</p>",
    "9": "<p>The proclamation is made throughout Judah and Jerusalem to bring to YHWH the contribution that Moses the servant of God had imposed on Israel in the wilderness. The connection to the wilderness Mosaic collection — the half-shekel tax for the tabernacle (Ex 30:11-16) — roots Joash's temple fundraising in the founding Mosaic pattern. The half-shekel was revived in Second Temple Judaism (cf. Matt 17:24-27: Peter's question about the temple tax, and Jesus' provision of the coin for both himself and Peter). Christ both fulfills and transcends the temple tax: he provides for it freely, while being 'the Son' who is technically exempt (Matt 17:25-26).</p>",
    "10": "<p>All the officials and all the people rejoiced and brought their contributions, casting them into the chest until they had finished. The joyful freewill character of the giving — 'all... rejoiced' (<em>wayyiśmᵉḥû kol-haśśārîm wᵉḵol-hāʿām</em>) — distinguishes it from the reluctant tax-payment the Levites had failed to collect (vv. 5-6). The NT equivalent is Paul's theology of cheerful giving: 'Each one must give as he has decided in his heart, not reluctantly or under compulsion, for God loves a cheerful giver' (2 Cor 9:7). The joyful temple collection under Joash is the OT pattern Paul applies to the new covenant community's support of the work of Christ.</p>",
    "11": "<p>Day after day the chest is brought to the king's officers, counted, emptied, and returned — a regular cycle of collection and disbursement for the temple work. The daily rhythm of the collection — recurring, consistent, institutional — types the new covenant's regular, sustained support of the ongoing work of the people of God. The daily collection that the early Jerusalem church maintained (Acts 6:1-2) follows the same institutional logic: a structured, regular distribution to support those who need and to fund the work of the community.</p>",
    "12": "<p>The king and Jehoiada give the collected money to the supervisors of the work for hiring stonecutters, carpenters, ironworkers, and bronze workers to restore the house of YHWH. The craftsman-teams assembled for temple restoration echo the original construction under Solomon: the same range of skilled trades, the same collaborative process of building the place of divine presence. Paul's image of the church as a building under construction ('each one's work will become manifest... it will be revealed by fire,' 1 Cor 3:12-15) draws on this OT temple-construction imagery for the new covenant community's ongoing building work.</p>",
    "13": "<p>The workers labor and the repair goes forward; they restore the house of God to its proper condition and strengthen it. The language 'its proper condition' (<em>ʾel-mattᵉkuntô*</em> — its proper measurement/specification) invokes the original building specifications as the standard to which the restored temple must conform. The restoration is not innovation but recovery of the founding intention. Christ comes not to abolish but to fulfill (Matt 5:17) — the new covenant's restoration of the covenant relationship to its founding intention, undoing the distortion of sin rather than inventing new terms.</p>",
    "14": "<p>When they had finished, they brought the remaining silver to the king and Jehoiada; temple vessels are made from it — spoons, ladles, gold and silver vessels. The surplus from the restoration project produces new vessels for ongoing worship. The new covenant's surplus-creating logic: Christ's work not only restores what was lost but generates abundance that overflows into new expressions of worship (John 10:10: 'I came that they may have life and have it abundantly'). The restoration surplus creating new vessels types the abundance of the new creation that overflows from Christ's completed work.</p>",
    "15": "<p>Jehoiada grows old to the fullness of days: 130 years old, full of days. The extraordinary lifespan of Jehoiada — exceeding the patriarchal spans of the post-flood era and approaching the antediluvian ages — marks him as a figure of covenant completeness. One hundred and thirty years old at death is exactly the age at which Adam fathered Seth (Gen 5:3), the genealogical ancestor through whom the covenant line runs to Noah. Jehoiada's life, dedicated entirely to preserving and restoring the Davidic covenant line, is the OT's most complete portrait of faithful priestly service — the priest who gives his life in service of the king types the interceding priest whose life sustains the covenant community.</p>",
    "16": "<p>Jehoiada is buried in the city of David among the kings because of the good he did in Israel, for God and his house. A priest buried among the kings — the single instance in Chronicles of a non-Davidic person receiving royal burial — is a Melchizedekian sign: the one who holds the priestly office has been granted the status of king. Ps 110:4, cited in Heb 5-7, establishes that the promised Davidic king will be 'a priest forever after the order of Melchizedek' — combining the priestly and royal offices in one person. Jehoiada's burial in the royal tombs is the historical instance of the priest-king fusion that Ps 110 predicts and Christ fulfills.</p>",
    "17": "<p>After the death of Jehoiada, the princes of Judah came and paid homage to the king; then the king listened to them. The king's immediate susceptibility to elite pressure once his priestly mentor is gone reveals the structural fragility of Joash's character: his faithfulness was borrowed, not intrinsic. The princes who lead him astray are the same class that had been restrained by Jehoiada's authority. The NT pattern of communities that remain faithful 'as long as...' (cf. Judg 2:7: 'the people served YHWH all the days of Joshua') is the chronic problem of leader-dependent faith that the new covenant addresses through the internal dwelling of the Spirit (Jer 31:33-34; Ezek 36:26-27).</p>",
    "18": "<p>They abandoned the house of YHWH, the God of their fathers, and served the Asherim and the idols; and wrath came upon Judah and Jerusalem because of their guilt. The abandonment of the restored temple — rebuilt at great effort in vv. 4-14 — for Asherah worship in the same reign shows the pattern of reformation without transformation: external renewal without internal change cannot produce sustained covenant faithfulness. The new covenant addresses this through regeneration: 'I will give you a new heart and put a new spirit within you' (Ezek 36:26). The restoration of the temple building without the restoration of the heart repeats Joash's tragedy in each generation that does not receive the new covenant's gift.</p>",
    "19": "<p>YHWH sent prophets among them to bring them back to himself; they testified against them, but they would not pay attention. The repeated sending of prophets to the repeatedly unfaithful people — prophet after prophet, testimony after testimony — is the OT's most sustained expression of divine patience. Matthew 21:33-44 (the parable of the tenants) draws this pattern to its conclusion: the owner sends servant after servant, and finally sends his son. The progressive sending of prophets climaxes in the sending of the Son; the pattern of rejection reaches its worst moment when the Son is killed. The rejected prophets of Joash's reign are the OT chapter of the story that Hebrews 1:1-2 summarizes.</p>",
    "20": "<p>The Spirit of God clothed (<em>lāḇᵉšāh</em>) Zechariah the son of Jehoiada the priest, and he stood above the people and said to them: 'Thus says God...' The Spirit-clothing of Zechariah is the prophetic commissioning formula at its most dramatic — the Spirit as garment worn by the prophet who speaks in the divine first person. Isaiah 61:1 — 'The Spirit of the Lord YHWH is upon me, because YHWH has anointed me to bring good news' — is the same Spirit-clothing experienced by the Servant, cited by Christ in Luke 4:18-19 as the manifesto of his mission. The Spirit who clothes Zechariah to speak YHWH's word is the Spirit who anoints Christ to proclaim the Year of Jubilee — the same commissioning, the greater messenger.</p>",
    "21": "<p>But they conspired against him, and by command of the king they stoned him with stones in the court of the house of YHWH. The death of the Spirit-clothed prophet, the son of the faithful priest, killed by the king he served, in the temple court — is the OT's most concentrated martyrdom narrative. Jesus cites this event in Matthew 23:35: 'so that on you may come all the righteous blood shed on earth, from the blood of righteous Abel to the blood of Zechariah the son of Barachiah [= Jehoiada], whom you murdered between the sanctuary and the altar.' Zechariah's death marks the end of the OT martyrological sequence; the stoning in the temple court is the type of the ultimate prophet's death outside the city gate. The temple court becomes the place of anti-witness: the Spirit-speaker silenced in the Spirit's own sanctuary.</p>",
    "22": "<p>Joash did not remember the kindness (<em>ḥesed</em>) that Jehoiada his father had shown him but killed his son. Zechariah's dying words: 'May YHWH see and avenge!' (<em>yireʾ YHWH wᵉyidrōš</em>). The dying martyr's prayer for divine retribution stands at the end of the OT's martyrological tradition. Stephen's dying prayer (Acts 7:60: 'Lord, do not hold this sin against them') is the NT's answer — the same structural moment (martyr dying among accusers) but the prayer inverted from retribution to forgiveness, because Christ's own death has already absorbed the retribution the martyrs' blood required. Christ's 'Father, forgive them; for they know not what they do' (Luke 23:34) is the first word from the cross that enables Stephen's prayer and completes the martyrological sequence that Zechariah's death initiated.</p>",
    "23": "<p>At the end of the year the army of Aram comes up against Joash — a small force that defeats a great army of Judah, because they had forsaken YHWH the God of their fathers. The covenantal reversal — few defeating many, the weak overcoming the strong — enacts the holy-war logic in reverse: when the covenant is broken, the normal divine arithmetic of holy war (one chasing a thousand) inverts. Lev 26:8 promised that five of Israel would chase a hundred; Lev 26:36-37 promised that in judgment they would flee when none pursues. The Aramean victory with a small force over Judah's army is the covenant curse theology enacted, the divine holy-war guarantee withdrawn.</p>",
    "24": "<p>The Arameans came with few men, yet YHWH delivered a very great army into their hand, because they had forsaken YHWH the God of their fathers. The explicit divine causation — 'YHWH delivered' (<em>nātan YHWH*</em>) the great army into the few Arameans' hands — reaffirms divine agency even in covenant judgment. YHWH who gives victory to the faithful gives defeat to the faithless through the same sovereignty. The cross enacts this logic definitively: God 'did not spare his own Son but gave him up for us all' (Rom 8:32), using the same vocabulary of divine giving (<em>paredōken</em>) to describe the supreme act of both judgment and grace.</p>",
    "25": "<p>The Arameans leave Joash severely wounded; his servants conspire against him for the blood of the son of Jehoiada the priest, and kill him in his bed. The blood of Zechariah — the martyr's prayer of v. 22 — is avenged through the king's own servants, who are motivated by the unjust killing. The king who rejected the covenant and killed the faithful prophet is destroyed by covenant-motivated vengeance. The NT parallel: those who reject and kill the prophets will face the blood-reckoning (Matt 23:35-36) that reaches its climax in the judgment of Jerusalem in 70 CE. Covenant faithfulness vindicates the martyrs; covenant rejection accumulates blood-guilt that eventually falls on the perpetrators.</p>",
    "26": "<p>The conspirators who kill Joash are Zabad son of Shimeath the Ammonite and Jehozabad son of Shimrith the Moabite — their mothers are explicitly identified as foreign women. The Chronicler's inclusion of the foreign maternal lineage (Ammonite and Moabite) of the king's assassins recalls Ruth the Moabite and the complex inclusion of gentile lineage in the covenant community. Here the gentile-descended servants perform the function of covenant avengers, executing judgment on the king who violated the covenant. The nations serve as instruments of divine justice even when Israel fails — the pattern the prophets develop and Paul articulates: 'Has God rejected his people? By no means!' (Rom 11:1), but the nations have been ingrafted into the covenant's judicial function.</p>",
    "27": "<p>Joash's sons, the many oracles against him, and the rebuilding of the house of God are written in the commentary (<em>midrāš</em>) of the Book of the Kings. His son Amaziah reigns in his place. The reference to the <em>midrāš</em> (the only pre-rabbinic use of this term in the OT as a literary designation) for Joash's reign — specifically the temple restoration narrative — suggests that the temple rebuilding under Joash generated an independent homiletical-exegetical commentary tradition even in the pre-exilic period. The temple rebuilding is important enough to produce its own interpretive literature; the new temple built through Christ's death ('Destroy this temple and in three days I will raise it,' John 2:19-21) generates the NT's own midrashic tradition of interpretation — the epistles and gospels as <em>midrāš</em> on the founding event of the new covenant.</p>"
  }
}

def main():
    c = load_comm('mkt-christ', '2chronicles')
    merge_comm(c, CHRIST)
    save_comm('mkt-christ', '2chronicles', c)
    count = sum(len(v) for v in CHRIST.values())
    print(f'2chronicles mkt-christ ch21-24: wrote {count} verses')

if __name__ == '__main__':
    main()
